-- ----------------------------------------------------------------------------
-- Events: Table: Events — top-level container (a festival, food bank shift, conference, etc.).
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS events (
  event_id                            TEXT                 PRIMARY KEY
);
ALTER TABLE events ADD COLUMN IF NOT EXISTS name TEXT;                                              -- Display name of the event.
ALTER TABLE events ADD COLUMN IF NOT EXISTS event_date TIMESTAMPTZ;
COMMENT ON TABLE events IS 'Table: Events — top-level container (a festival, food bank shift, conference, etc.).';
