-- ----------------------------------------------------------------------------
-- Volunteers: Table: Volunteers — people available to be slotted into shifts.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS volunteers (
  volunteer_id                        TEXT                 PRIMARY KEY
);
ALTER TABLE volunteers ADD COLUMN IF NOT EXISTS first_name TEXT;
ALTER TABLE volunteers ADD COLUMN IF NOT EXISTS last_name TEXT;
ALTER TABLE volunteers ADD COLUMN IF NOT EXISTS email_address TEXT;                                 -- Used as the click-to-login identity.
ALTER TABLE volunteers ADD COLUMN IF NOT EXISTS reliability_score NUMERIC;                          -- 0..1 — coordinator's confidence the volunteer will show up. Drives per-shift coverage weighting.
ALTER TABLE volunteers ADD COLUMN IF NOT EXISTS max_hours NUMERIC;                                  -- Volunteer's stated maximum hours for this scheduling period.
COMMENT ON TABLE volunteers IS 'Table: Volunteers — people available to be slotted into shifts.';
COMMENT ON COLUMN volunteers.email_address IS 'Used as the click-to-login identity.';
COMMENT ON COLUMN volunteers.reliability_score IS '0..1 — coordinator''s confidence the volunteer will show up. Drives per-shift coverage weighting.';
COMMENT ON COLUMN volunteers.max_hours IS 'Volunteer''s stated maximum hours for this scheduling period.';

-- ----------------------------------------------------------------------------
-- Shifts: Table: Shifts — a time block within an event needing N people with a required skill.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS shifts (
  shift_id                            TEXT                 PRIMARY KEY
);
ALTER TABLE shifts ADD COLUMN IF NOT EXISTS name TEXT;                                              -- Short label (e.g. "Setup Morning").
ALTER TABLE shifts ADD COLUMN IF NOT EXISTS event TEXT;                                             -- Parent event.
ALTER TABLE shifts ADD COLUMN IF NOT EXISTS required_skill TEXT;                                    -- Free-text skill tag (e.g. "setup", "intake", "food-handler").
ALTER TABLE shifts ADD COLUMN IF NOT EXISTS duration_hours NUMERIC;                                 -- Length of the shift in hours; drives per-volunteer load.
ALTER TABLE shifts ADD COLUMN IF NOT EXISTS needed_count INTEGER;                                   -- How many volunteers the coordinator wants on this shift.
COMMENT ON TABLE shifts IS 'Table: Shifts — a time block within an event needing N people with a required skill.';
COMMENT ON COLUMN shifts.name IS 'Short label (e.g. "Setup Morning").';
COMMENT ON COLUMN shifts.event IS 'Parent event.';
COMMENT ON COLUMN shifts.required_skill IS 'Free-text skill tag (e.g. "setup", "intake", "food-handler").';
COMMENT ON COLUMN shifts.duration_hours IS 'Length of the shift in hours; drives per-volunteer load.';
COMMENT ON COLUMN shifts.needed_count IS 'How many volunteers the coordinator wants on this shift.';

-- ----------------------------------------------------------------------------
-- Assignments: Table: Assignments — a volunteer slotted into a shift. Join table between Volunteers and Shifts (ERB does not allow direct many-to-many).
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS assignments (
  assignment_id                       TEXT                 PRIMARY KEY
);
ALTER TABLE assignments ADD COLUMN IF NOT EXISTS volunteer TEXT;
ALTER TABLE assignments ADD COLUMN IF NOT EXISTS shift TEXT;
COMMENT ON TABLE assignments IS 'Table: Assignments — a volunteer slotted into a shift. Join table between Volunteers and Shifts (ERB does not allow direct many-to-many).';

